#include <sys/sysinfo.h>
#include "syscall.h"

#define klong long long
#define kulong unsigned long long

struct kernel_sysinfo {
	klong uptime;
	kulong loads[3];
	kulong totalram;
	kulong freeram;
	kulong sharedram;
	kulong bufferram;
	kulong totalswap;
	kulong freeswap;
	short procs;
	short pad;
	kulong totalhigh;
	kulong freehigh;
	unsigned mem_unit;
};

int __lsysinfo(struct sysinfo *info)
{
	struct kernel_sysinfo tmp;
	int ret = syscall(SYS_sysinfo, &tmp);
	if(ret == -1) return ret;
	info->uptime = tmp.uptime;
	info->loads[0] = tmp.loads[0];
	info->loads[1] = tmp.loads[1];
	info->loads[2] = tmp.loads[2];
	kulong shifts;
	kulong max = tmp.totalram | tmp.totalswap;
	__asm__("bsr %1,%0" : "=r"(shifts) : "r"(max));
	shifts = shifts >= 32 ? shifts - 31 : 0;
	info->totalram = tmp.totalram >> shifts;
	info->freeram = tmp.freeram >> shifts;
	info->sharedram = tmp.sharedram >> shifts;
	info->bufferram = tmp.bufferram >> shifts;
	info->totalswap = tmp.totalswap >> shifts;
	info->freeswap = tmp.freeswap >> shifts;
	info->procs = tmp.procs ;
	info->totalhigh = tmp.totalhigh >> shifts;
	info->freehigh = tmp.freehigh >> shifts;
	info->mem_unit = (tmp.mem_unit ? tmp.mem_unit : 1) << shifts;
	return ret;
}

weak_alias(__lsysinfo, sysinfo);

#include "jemalloc/internal/jemalloc_preamble.h"

#include "jemalloc/internal/mutex.h"
#include "jemalloc/internal/prof.h"
#include "jemalloc/internal/prof_stats.h"

bool                opt_prof_stats = false;
malloc_mutex_t      prof_stats_mtx;
static prof_stats_t prof_stats_live[PROF_SC_NSIZES];
static prof_stats_t prof_stats_accum[PROF_SC_NSIZES];

static void
prof_stats_enter(tsd_t *tsd, szind_t ind) {
	assert(opt_prof && opt_prof_stats);
	assert(ind < SC_NSIZES);
	malloc_mutex_lock(tsd_tsdn(tsd), &prof_stats_mtx);
}

static void
prof_stats_leave(tsd_t *tsd) {
	malloc_mutex_unlock(tsd_tsdn(tsd), &prof_stats_mtx);
}

void
prof_stats_inc(tsd_t *tsd, szind_t ind, size_t size) {
	cassert(config_prof);
	prof_stats_enter(tsd, ind);
	prof_stats_live[ind].req_sum += size;
	prof_stats_live[ind].count++;
	prof_stats_accum[ind].req_sum += size;
	prof_stats_accum[ind].count++;
	prof_stats_leave(tsd);
}

void
prof_stats_dec(tsd_t *tsd, szind_t ind, size_t size) {
	cassert(config_prof);
	prof_stats_enter(tsd, ind);
	prof_stats_live[ind].req_sum -= size;
	prof_stats_live[ind].count--;
	prof_stats_leave(tsd);
}

void
prof_stats_get_live(tsd_t *tsd, szind_t ind, prof_stats_t *stats) {
	cassert(config_prof);
	prof_stats_enter(tsd, ind);
	memcpy(stats, &prof_stats_live[ind], sizeof(prof_stats_t));
	prof_stats_leave(tsd);
}

void
prof_stats_get_accum(tsd_t *tsd, szind_t ind, prof_stats_t *stats) {
	cassert(config_prof);
	prof_stats_enter(tsd, ind);
	memcpy(stats, &prof_stats_accum[ind], sizeof(prof_stats_t));
	prof_stats_leave(tsd);
}
